const n={"ec2.public_ip":{cloud:"aws",title:"EC2 Instance Has Public IP",what:"One or more EC2 instances have a public IP address directly assigned.",why:"Publicly reachable instances expand your attack surface. Any open port becomes externally accessible.",fix:["Place instances behind an Application Load Balancer (ALB) or NAT Gateway.",'Remove the public IP by disabling "Auto-assign public IP" in the subnet settings.',"Restrict Security Group inbound rules to known IP ranges only."],docs:"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-instance-addressing.html",severity:"medium"},"ec2.vulnerable_ami":{cloud:"aws",title:"EC2 Using Vulnerable or Deprecated AMI",what:"Instances are running on AMIs that are outdated, deprecated, or have known CVEs.",why:"Unpatched AMIs are a common initial access vector in cloud breaches.",fix:["Build a new AMI from the latest Amazon Linux 2023 / Ubuntu 22.04 LTS base.","Enable EC2 Image Builder to auto-refresh AMIs on a schedule.","Replace running instances with new ones using the updated AMI."],docs:"https://docs.aws.amazon.com/imagebuilder/latest/userguide/what-is-image-builder.html",severity:"high"},"ec2.missing_tags":{cloud:"aws",title:"EC2 Instance Missing Required Tags",what:"Instances are missing required tags (e.g. Owner, Environment, CostCenter).",why:"Missing tags make cost attribution, incident response, and compliance auditing difficult.",fix:["Define a tagging policy using AWS Organizations Tag Policies.",'Use AWS Config rule "required-tags" to enforce tagging compliance.',"Apply tags via IaC (Terraform/CloudFormation) to all new resources."],docs:"https://docs.aws.amazon.com/tag-editor/latest/userguide/tagging.html",severity:"low"},"s3.public_access":{cloud:"aws",title:"S3 Bucket Publicly Accessible",what:"S3 bucket has public access enabled — either via ACL, bucket policy, or missing Block Public Access settings.",why:"Public S3 buckets are responsible for some of the largest data breaches. Sensitive data can be read or overwritten by anyone.",fix:['Enable "Block all public access" on the bucket in the AWS Console or via CLI.','Remove any ACL grants to "Everyone" or "Any authenticated AWS user".','Review bucket policy for `"Principal": "*"` statements and restrict them.',"Use AWS Macie to scan for sensitive data in at-risk buckets."],docs:"https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-control-block-public-access.html",severity:"critical"},"s3.no_encryption":{cloud:"aws",title:"S3 Bucket Not Encrypted at Rest",what:"Server-side encryption (SSE) is not enabled on this bucket.",why:"Without encryption at rest, bucket data is readable if storage is physically compromised.",fix:["Enable SSE-S3 (AES-256) or SSE-KMS on the bucket.","Use a bucket policy to deny `s3:PutObject` requests without `x-amz-server-side-encryption`.","Prefer SSE-KMS with a customer-managed key for additional access control."],docs:"https://docs.aws.amazon.com/AmazonS3/latest/userguide/serv-side-encryption.html",severity:"high"},"s3.no_versioning":{cloud:"aws",title:"S3 Bucket Versioning Disabled",what:"Object versioning is not enabled, so deleted or overwritten objects cannot be recovered.",why:"Without versioning, ransomware or accidental deletion permanently destroys data.",fix:["Enable versioning on the bucket.","Configure lifecycle rules to expire old versions and control storage costs.","Enable MFA Delete for buckets containing critical data."],docs:"https://docs.aws.amazon.com/AmazonS3/latest/userguide/Versioning.html",severity:"medium"},"iam.wildcard_action":{cloud:"aws",title:"IAM Policy Grants Wildcard Actions (*)",what:'An IAM policy contains `"Action": "*"` granting unrestricted permissions.',why:"Wildcard actions violate least-privilege principle and allow privilege escalation.",fix:['Replace `"Action": "*"` with only the specific actions the role needs.',"Use AWS IAM Access Analyzer to generate least-privilege policies from CloudTrail.","Regularly review and prune unused permissions with IAM Access Advisor."],docs:"https://docs.aws.amazon.com/IAM/latest/UserGuide/best-practices.html#grant-least-privilege",severity:"critical"},"iam.admin_policy":{cloud:"aws",title:"IAM User or Role Has Admin Policy Attached",what:"AdministratorAccess or a similar all-encompassing policy is attached.",why:"Admin accounts are high-value targets. Compromise leads to full account takeover.",fix:["Remove AdministratorAccess and replace with scoped policies.","Use IAM roles with short-lived credentials (STS) instead of long-term admin keys.","Enable MFA on all admin accounts.","Use AWS Organizations SCPs to restrict admin actions at the org level."],docs:"https://docs.aws.amazon.com/IAM/latest/UserGuide/access_policies_job-functions.html",severity:"critical"},"iam.unused_keys":{cloud:"aws",title:"IAM Access Key Unused for 90+ Days",what:"Long-lived access keys that have not been used in over 90 days still exist.",why:"Unused credentials are a dormant risk — if leaked, attackers can use them unnoticed.",fix:["Rotate or delete access keys unused for more than 90 days.","Use IAM roles instead of long-term access keys wherever possible.","Enable AWS Credential Reports to regularly audit key usage."],docs:"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_credentials_access-keys.html",severity:"high"},"sg.ssh_open":{cloud:"aws",title:"SSH Port 22 Open to the World (0.0.0.0/0)",what:"Security group allows inbound SSH (port 22) from any IP address.",why:"Open SSH is constantly scanned and brute-forced by automated bots across the internet.",fix:["Restrict SSH to your office/VPN IP ranges only.","Remove direct SSH access entirely — use AWS Systems Manager Session Manager instead.","If SSH is needed, place it behind a bastion host with strict security group rules."],docs:"https://docs.aws.amazon.com/systems-manager/latest/userguide/session-manager.html",severity:"critical"},"sg.rdp_open":{cloud:"aws",title:"RDP Port 3389 Open to the World (0.0.0.0/0)",what:"Security group allows inbound RDP (port 3389) from any IP address.",why:"Open RDP is one of the most common ransomware entry points.",fix:["Restrict RDP to VPN or specific IP ranges only.","Use AWS Systems Manager Fleet Manager for remote desktop instead of direct RDP.","Enable Network Access Control Lists (NACLs) as a secondary layer."],docs:"https://docs.aws.amazon.com/systems-manager/latest/userguide/fleet-rdp.html",severity:"critical"},"sg.all_traffic":{cloud:"aws",title:"Security Group Allows All Inbound Traffic",what:"A security group rule allows all ports and protocols from any source.",why:"This effectively disables the firewall, exposing every running service to the internet.",fix:["Replace the open rule with specific port/protocol rules for only what is needed.","Audit each running service and only allow its specific port.","Use VPC Flow Logs to understand actual traffic before tightening rules."],docs:"https://docs.aws.amazon.com/vpc/latest/userguide/vpc-security-groups.html",severity:"critical"},"rds.publicly_accessible":{cloud:"aws",title:"RDS Database Publicly Accessible",what:'The RDS instance has the "Publicly Accessible" flag set to true.',why:"A publicly accessible database can be discovered and attacked from the internet.",fix:['Set "Publicly Accessible" to false — databases should only be in private subnets.',"Use a bastion host or AWS Systems Manager for administrative access.","Ensure the DB is in a private VPC subnet with no internet gateway route."],docs:"https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_VPC.WorkingWithRDSInstanceinaVPC.html",severity:"critical"},"rds.no_encryption":{cloud:"aws",title:"RDS Database Storage Not Encrypted",what:"The RDS instance does not have storage encryption enabled.",why:"Unencrypted database storage can expose sensitive data if snapshots or storage are compromised.",fix:["Enable encryption by creating a new encrypted snapshot and restoring to a new instance.","Note: encryption cannot be enabled on a running instance — a snapshot restore is required.","Use a KMS customer-managed key for additional control over key rotation."],docs:"https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Overview.Encryption.html",severity:"high"},"lambda.hardcoded_secret":{cloud:"aws",title:"Hardcoded Secret Detected in Lambda Function",what:"Environment variables or function code contains what appears to be a hardcoded secret, API key, or password.",why:"Hardcoded credentials are exposed to anyone with Lambda describe/list access and are difficult to rotate.",fix:["Move secrets to AWS Secrets Manager or Parameter Store (SecureString).","Update the Lambda function to fetch secrets at runtime using the AWS SDK.","Revoke and rotate any exposed credentials immediately.","Use AWS Macie to scan for additional exposed secrets."],docs:"https://docs.aws.amazon.com/secretsmanager/latest/userguide/lambda-functions.html",severity:"critical"},"cloudtrail.disabled":{cloud:"aws",title:"CloudTrail Not Enabled or Not Multi-Region",what:"CloudTrail is either disabled or only logging in a single region.",why:"Without CloudTrail you have no audit log of API calls — impossible to detect breaches or do forensics.",fix:["Enable CloudTrail with multi-region logging.","Enable CloudTrail log file validation to detect tampering.","Deliver logs to a separate S3 bucket in a dedicated security account.","Set up CloudWatch Alarms for suspicious CloudTrail events."],docs:"https://docs.aws.amazon.com/awscloudtrail/latest/userguide/cloudtrail-create-and-update-a-trail.html",severity:"critical"},"ebs.unencrypted":{cloud:"aws",title:"EBS Volume Not Encrypted",what:"One or more EBS volumes do not have encryption at rest enabled.",why:"Unencrypted EBS volumes can expose data if snapshots are shared or volumes are detached.",fix:["Enable EBS default encryption at the account level so all new volumes are encrypted.","For existing volumes: create an encrypted snapshot and restore to a new encrypted volume.","Use KMS customer-managed keys for stricter access control."],docs:"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/EBSEncryption.html",severity:"high"},"eks.public_endpoint":{cloud:"aws",title:"EKS API Server Endpoint is Publicly Accessible",what:"The EKS cluster API server endpoint is accessible from the public internet.",why:"A public Kubernetes API server is a prime target for credential theft and cluster takeover.",fix:["Restrict API server access to specific CIDR blocks (your office/VPN).","Enable the private endpoint and disable the public endpoint entirely.","Ensure RBAC is configured with least-privilege roles."],docs:"https://docs.aws.amazon.com/eks/latest/userguide/cluster-endpoint.html",severity:"high"},"guardduty.disabled":{cloud:"aws",title:"AWS GuardDuty Not Enabled",what:"GuardDuty threat detection is not enabled in this region.",why:"Without GuardDuty, malicious activity (crypto mining, credential exfiltration, port scanning) goes undetected.",fix:["Enable GuardDuty in all active regions.","Enable GuardDuty at the AWS Organizations level to cover all accounts.","Configure SNS notifications or EventBridge rules for high-severity findings."],docs:"https://docs.aws.amazon.com/guardduty/latest/ug/guardduty_settingup.html",severity:"high"},"kms.no_rotation":{cloud:"aws",title:"KMS Key Auto-Rotation Disabled",what:"Customer-managed KMS keys do not have automatic key rotation enabled.",why:"Without rotation, a compromised key provides indefinite access to encrypted data.",fix:["Enable automatic annual key rotation in KMS key settings.","AWS rotates only the key material — the key ID remains the same, no re-encryption needed."],docs:"https://docs.aws.amazon.com/kms/latest/developerguide/rotate-keys.html",severity:"medium"},"vpc.default_in_use":{cloud:"aws",title:"Default VPC Is In Use",what:"Resources are deployed in the default VPC which has permissive settings.",why:"Default VPCs allow all instances to have public IPs and have open inter-instance communication.",fix:["Create a custom VPC with private subnets and a NAT Gateway.","Migrate workloads from the default VPC to the custom VPC.","Delete the default VPC from all regions once workloads are migrated."],docs:"https://docs.aws.amazon.com/vpc/latest/userguide/default-vpc.html",severity:"medium"},"vpc.no_flow_logs":{cloud:"aws",title:"VPC Flow Logs Not Enabled",what:"VPC Flow Logs are not configured for network traffic monitoring.",why:"Without flow logs, you cannot detect anomalous traffic, data exfiltration, or port scanning.",fix:["Enable VPC Flow Logs and deliver to CloudWatch Logs or S3.","Set up CloudWatch Metric Filters to alert on suspicious traffic patterns."],docs:"https://docs.aws.amazon.com/vpc/latest/userguide/flow-logs.html",severity:"medium"},"alb.no_waf":{cloud:"aws",title:"Load Balancer Has No WAF Web ACL",what:"The Application Load Balancer does not have a WAF Web ACL attached.",why:"Without WAF, common web attacks (SQL injection, XSS, DDoS) reach your application directly.",fix:["Create a WAF Web ACL with AWS Managed Rule Groups (Core Rule Set, Known Bad Inputs).","Associate the Web ACL with the ALB.","Enable AWS Shield Advanced for DDoS protection on critical ALBs."],docs:"https://docs.aws.amazon.com/waf/latest/developerguide/waf-chapter.html",severity:"high"},"alb.no_access_logs":{cloud:"aws",title:"ALB Access Logging Disabled",what:"Access logs are not enabled for the Application Load Balancer.",why:"Without access logs, you cannot investigate request patterns, attacks, or performance issues.",fix:["Enable access logging on the ALB and point it to an S3 bucket.","Set a lifecycle policy on the S3 bucket to retain logs for at least 90 days."],docs:"https://docs.aws.amazon.com/elasticloadbalancing/latest/application/load-balancer-access-logs.html",severity:"medium"},"dynamodb.no_pitr":{cloud:"aws",title:"DynamoDB Point-in-Time Recovery (PITR) Disabled",what:"PITR is not enabled, meaning accidental data loss cannot be recovered.",why:"Without PITR, accidental deletes or table corruption result in permanent data loss.",fix:["Enable PITR on all DynamoDB tables holding important data.","Test recovery procedures at least quarterly."],docs:"https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/PointInTimeRecovery.html",severity:"medium"},"ecr.critical_cve":{cloud:"aws",title:"Container Image Has Critical CVEs",what:"ECR image scan found critical or high severity CVEs in container images.",why:"Container vulnerabilities can be exploited for container escape, privilege escalation, or data theft.",fix:["Update the base image to the latest version.","Rebuild and push a patched image immediately.","Enable scan-on-push to catch vulnerabilities before they reach production.","Use Amazon Inspector for continuous container vulnerability monitoring."],docs:"https://docs.aws.amazon.com/AmazonECR/latest/userguide/image-scanning.html",severity:"critical"},"ecr.no_scan_on_push":{cloud:"aws",title:"ECR Repository Has Scan-on-Push Disabled",what:"Container images are pushed to ECR without being automatically scanned for vulnerabilities.",why:"Unscanned images may contain known CVEs that could have been caught at build time.",fix:["Enable scan-on-push for all ECR repositories.","Configure EventBridge rules to alert on critical scan findings."],docs:"https://docs.aws.amazon.com/AmazonECR/latest/userguide/image-scanning.html",severity:"high"},"gcp.compute.public_ip":{cloud:"gcp",title:"Compute VM Has External (Public) IP",what:"A Compute Engine VM instance has an external IP address directly attached.",why:"VMs with external IPs are directly reachable from the internet, increasing the attack surface.",fix:["Remove the external IP from the VM network interface.","Use Cloud NAT to give VMs internet egress without a public ingress IP.","Route external traffic through a Cloud Load Balancer instead."],docs:"https://cloud.google.com/compute/docs/ip-addresses/reserve-static-external-ip-address",severity:"medium"},"gcp.compute.serial_port_enabled":{cloud:"gcp",title:"Serial Port Access Enabled on VM",what:"Interactive serial port access is enabled on a Compute Engine instance.",why:"Serial port access bypasses normal network controls and can be used by attackers with IAM access.",fix:["Disable serial port access in the VM metadata: set `serial-port-enable` to `false`.","Use OS Login or SSH keys for legitimate administrative access.","Enforce this with an Organisation Policy: `compute.disableSerialPortAccess`."],docs:"https://cloud.google.com/compute/docs/troubleshooting/troubleshooting-using-serial-console",severity:"medium"},"gcp.compute.os_not_patched":{cloud:"gcp",title:"Compute VM OS Not Patched",what:"The VM is running an OS version with known unpatched vulnerabilities.",why:"Unpatched systems are the primary entry vector for both automated and targeted attacks.",fix:["Enable OS patch management using VM Manager patch jobs.","Schedule recurring patch deployments across your VM fleet.","Use Container-Optimized OS or Shielded VMs for increased security baseline."],docs:"https://cloud.google.com/compute/docs/os-patch-management",severity:"high"},"gcp.storage.public_bucket":{cloud:"gcp",title:"Cloud Storage Bucket is Publicly Accessible",what:"The GCS bucket has `allUsers` or `allAuthenticatedUsers` in its IAM policy.",why:"Public buckets expose all stored objects to anyone on the internet, risking data leakage.",fix:["Remove `allUsers` and `allAuthenticatedUsers` from all bucket IAM bindings.","Enable Uniform Bucket-Level Access to disable legacy ACLs.","Use Signed URLs or Identity-Aware Proxy for controlled public access.","Enable GCS audit logs and use Security Command Center to alert on public buckets."],docs:"https://cloud.google.com/storage/docs/access-control/making-data-public",severity:"critical"},"gcp.storage.no_encryption":{cloud:"gcp",title:"Cloud Storage Not Using Customer-Managed Encryption Keys (CMEK)",what:"Buckets are using Google-managed encryption keys instead of customer-managed keys.",why:"Without CMEK, you have no control over key rotation, revocation, or access auditing for encrypted data.",fix:["Create a Cloud KMS key ring and key for each sensitive bucket.","Set the default encryption key on the bucket to your CMEK.","Rotate CMEK keys at least annually."],docs:"https://cloud.google.com/storage/docs/encryption/customer-managed-keys",severity:"medium"},"gcp.storage.no_versioning":{cloud:"gcp",title:"Cloud Storage Versioning Disabled",what:"Object versioning is not enabled on the bucket.",why:"Without versioning, deleted or overwritten objects cannot be recovered.",fix:["Enable versioning on the bucket via `gsutil versioning set on gs://BUCKET_NAME`.","Set Object Lifecycle Management rules to expire old versions after N days."],docs:"https://cloud.google.com/storage/docs/object-versioning",severity:"medium"},"gcp.iam.service_account_key":{cloud:"gcp",title:"Service Account Has User-Managed Keys",what:"A service account has one or more user-created and managed keys.",why:"User-managed keys are long-lived credentials that are easily leaked and hard to rotate.",fix:["Delete all user-managed service account keys.","Use Workload Identity for GKE workloads, or the metadata server for Compute Engine.","If keys are unavoidable, store them in Secret Manager and rotate every 90 days."],docs:"https://cloud.google.com/iam/docs/best-practices-for-managing-service-account-keys",severity:"high"},"gcp.iam.primitive_roles":{cloud:"gcp",title:"Primitive IAM Roles (Owner/Editor/Viewer) in Use",what:"Project-level primitive roles (roles/owner, roles/editor) are assigned.",why:"Primitive roles grant overly broad permissions and violate least-privilege principle.",fix:["Replace roles/owner and roles/editor with predefined or custom roles.","Use IAM Recommender to get least-privilege role suggestions.","Enable Policy Analyzer to audit who has access to what."],docs:"https://cloud.google.com/iam/docs/understanding-roles#primitive_roles",severity:"high"},"gcp.iam.no_mfa":{cloud:"gcp",title:"Users Without Multi-Factor Authentication (MFA)",what:"Some Google accounts in your organisation do not have MFA/2-Step Verification enabled.",why:"Without MFA, a stolen password is sufficient to compromise an account.",fix:["Enforce 2-Step Verification for all users via Google Workspace Admin.","Require hardware security keys (FIDO2) for privileged accounts.","Use Context-Aware Access to require MFA for sensitive resource access."],docs:"https://support.google.com/a/answer/9176657",severity:"critical"},"gcp.firewall.ssh_open":{cloud:"gcp",title:"Firewall Rule Allows SSH from 0.0.0.0/0",what:"A VPC firewall rule allows inbound SSH (TCP 22) from any source IP.",why:"Open SSH ports are continuously scanned and attacked by automated tools globally.",fix:["Delete or restrict the firewall rule to specific known IP ranges.","Use Identity-Aware Proxy (IAP) for TCP tunnelling — it provides SSH access without open firewall rules.","Enable OS Login for centrally managed, short-lived SSH access."],docs:"https://cloud.google.com/iap/docs/using-tcp-forwarding",severity:"critical"},"gcp.firewall.rdp_open":{cloud:"gcp",title:"Firewall Rule Allows RDP from 0.0.0.0/0",what:"A VPC firewall rule allows inbound RDP (TCP 3389) from any source IP.",why:"Publicly exposed RDP is a top ransomware entry point.",fix:["Restrict the firewall rule to only your corporate/VPN IP ranges.","Use IAP for TCP tunnelling to remove the need for any open RDP firewall rule.","Enable Cloud Armor to protect internet-facing endpoints."],docs:"https://cloud.google.com/iap/docs/using-tcp-forwarding",severity:"critical"},"gcp.vpc.no_flow_logs":{cloud:"gcp",title:"VPC Flow Logs Not Enabled",what:"VPC flow logging is disabled for one or more subnets.",why:"Without flow logs, you cannot investigate network anomalies, lateral movement, or data exfiltration.",fix:["Enable VPC Flow Logs on all subnets via the Cloud Console or gcloud.","Export flow logs to Cloud Logging and set up Log-Based Alerts for anomalous patterns."],docs:"https://cloud.google.com/vpc/docs/using-flow-logs",severity:"medium"},"gcp.sql.public_ip":{cloud:"gcp",title:"Cloud SQL Instance Has Public IP",what:"The Cloud SQL instance has a public IP address and is reachable from the internet.",why:"A publicly accessible database is a high-value target for brute-force and injection attacks.",fix:["Switch the instance to Private IP only — remove the public IP.","Use Cloud SQL Auth Proxy for all connection from applications and admin tools.","Place the instance in a VPC with restricted IP authorisation."],docs:"https://cloud.google.com/sql/docs/mysql/configure-private-ip",severity:"critical"},"gcp.sql.no_backup":{cloud:"gcp",title:"Cloud SQL Automated Backups Disabled",what:"Automated backups are not enabled for the Cloud SQL instance.",why:"Without backups, data loss from corruption or accidental deletion is unrecoverable.",fix:["Enable automated backups in the Cloud SQL instance settings.","Configure a backup retention window of at least 7 days.","Enable point-in-time recovery (PITR) for additional granularity."],docs:"https://cloud.google.com/sql/docs/mysql/backup-recovery/backups",severity:"high"},"gcp.gke.public_endpoint":{cloud:"gcp",title:"GKE Cluster Has Public API Server Endpoint",what:"The GKE cluster control plane is accessible from the public internet.",why:"A public Kubernetes API server is a prime target for credential theft and cluster takeover.",fix:["Enable Private Cluster mode to remove the public endpoint.","If a public endpoint is required, use Master Authorised Networks to restrict access to known IPs.","Ensure RBAC and Workload Identity are configured."],docs:"https://cloud.google.com/kubernetes-engine/docs/how-to/private-clusters",severity:"high"},"gcp.gke.legacy_abac":{cloud:"gcp",title:"GKE Legacy ABAC (Attribute-Based Access Control) Enabled",what:"The GKE cluster is using the legacy ABAC authorisation system.",why:"Legacy ABAC is coarse-grained and bypasses Kubernetes RBAC policies.",fix:["Disable Legacy ABAC on the cluster.","Use Kubernetes RBAC exclusively for fine-grained access control.","Review and update all service account bindings to use RBAC roles."],docs:"https://cloud.google.com/kubernetes-engine/docs/how-to/role-based-access-control",severity:"high"},"gcp.logging.disabled":{cloud:"gcp",title:"Cloud Audit Logging Not Fully Enabled",what:"Admin Activity, Data Access, or System Event audit logs are not enabled for one or more services.",why:"Without audit logs, you cannot detect unauthorised access or reconstruct incident timelines.",fix:["Enable all audit log types (Admin Activity, Data Access, System Event) at the project level.","Export logs to Cloud Storage or BigQuery for long-term retention.","Set up Log-Based Alerts for critical events (IAM changes, key deletions, etc.)."],docs:"https://cloud.google.com/logging/docs/audit",severity:"critical"},"gcp.monitoring.no_alerts":{cloud:"gcp",title:"No Security Monitoring Alerts Configured",what:"No alerting policies exist for critical security events in Cloud Monitoring.",why:"Without alerts, security incidents go undetected until they cause visible damage.",fix:["Create alerting policies for: IAM policy changes, firewall rule modifications, bucket ACL changes.","Integrate Cloud Monitoring with PagerDuty, Slack, or email for timely notification.","Use Security Command Center Premium for automated threat detection."],docs:"https://cloud.google.com/monitoring/alerts",severity:"high"},"gcp.kms.no_rotation":{cloud:"gcp",title:"Cloud KMS Key Rotation Not Configured",what:"Customer-managed encryption keys (CMEK) do not have automatic rotation enabled.",why:"Without rotation, a compromised key gives indefinite access to all data encrypted with it.",fix:["Enable automatic rotation on Cloud KMS keys (recommended: 90 days).","Rotation creates a new key version; old versions remain for decryption until destroyed.","Use separate key rings per environment (dev/staging/prod)."],docs:"https://cloud.google.com/kms/docs/key-rotation",severity:"medium"},"azure.vm.public_ip":{cloud:"azure",title:"Azure VM Has Public IP Address",what:"A Virtual Machine has a public IP directly attached to its NIC.",why:"Internet-facing VMs are continuously scanned for vulnerabilities and open ports.",fix:["Dissociate the public IP from the VM NIC.","Place the VM behind an Azure Load Balancer or Application Gateway.","Use Azure Bastion for secure administrative access instead of direct RDP/SSH."],docs:"https://learn.microsoft.com/en-us/azure/bastion/bastion-overview",severity:"medium"},"azure.vm.no_disk_encryption":{cloud:"azure",title:"Azure VM Disk Not Encrypted",what:"The VM OS or data disks are not encrypted with Azure Disk Encryption (ADE).",why:"Unencrypted disks expose data at rest if the underlying hardware is compromised.",fix:["Enable Azure Disk Encryption (ADE) using Azure Key Vault for key management.","Use Server-Side Encryption (SSE) with Customer-Managed Keys (CMK) as a minimum.","Apply Azure Policy to enforce disk encryption across all VMs in the subscription."],docs:"https://learn.microsoft.com/en-us/azure/virtual-machines/disk-encryption-overview",severity:"high"},"azure.vm.no_mde":{cloud:"azure",title:"Microsoft Defender for Endpoint Not Enabled on VM",what:"Microsoft Defender for Endpoint (MDE) is not deployed on the Virtual Machine.",why:"Without EDR coverage, malware, lateral movement, and ransomware can run undetected on the VM.",fix:["Enable Microsoft Defender for Servers in Defender for Cloud.","Deploy the MDE extension to all VMs via Azure Policy.","Review Defender for Cloud security score to identify other unprotected resources."],docs:"https://learn.microsoft.com/en-us/azure/defender-for-cloud/integration-defender-for-endpoint",severity:"high"},"azure.storage.public_blob":{cloud:"azure",title:"Azure Storage Account Allows Public Blob Access",what:"The storage account has public blob access enabled, allowing anonymous reads.",why:"Publicly accessible blobs expose sensitive files to anyone who knows (or guesses) the URL.",fix:["Set `allowBlobPublicAccess` to `false` on the storage account.","Use Shared Access Signatures (SAS) or Azure AD authentication for controlled access.","Enable Azure Defender for Storage to detect anomalous access patterns."],docs:"https://learn.microsoft.com/en-us/azure/storage/blobs/anonymous-read-access-prevent",severity:"critical"},"azure.storage.no_https":{cloud:"azure",title:"Azure Storage Account Allows HTTP (Non-HTTPS) Traffic",what:"The storage account does not enforce HTTPS-only connections.",why:"HTTP traffic is unencrypted; credentials and data can be intercepted in transit.",fix:['Enable "Secure transfer required" on the storage account.',"Apply Azure Policy `Secure transfer to storage accounts should be enabled` to enforce this."],docs:"https://learn.microsoft.com/en-us/azure/storage/common/storage-require-secure-transfer",severity:"high"},"azure.storage.no_cmk":{cloud:"azure",title:"Azure Storage Not Using Customer-Managed Keys (CMK)",what:"The storage account uses Microsoft-managed keys instead of customer-managed keys.",why:"Without CMK, you cannot control key rotation, revocation, or access auditing.",fix:["Create an Azure Key Vault and add a key.","Configure the storage account to use the Key Vault key via managed identity.","Enable automatic key rotation in Key Vault."],docs:"https://learn.microsoft.com/en-us/azure/storage/common/customer-managed-keys-overview",severity:"medium"},"azure.iam.no_mfa":{cloud:"azure",title:"Azure AD Users Without MFA",what:"One or more Azure AD user accounts do not have multi-factor authentication enabled.",why:"MFA prevents account takeover even when credentials are compromised.",fix:["Enable Conditional Access policies requiring MFA for all users.","Use Microsoft Authenticator app or FIDO2 hardware keys.","Enable Microsoft Entra ID Protection to detect risky sign-ins automatically."],docs:"https://learn.microsoft.com/en-us/entra/identity/authentication/tutorial-enable-azure-mfa",severity:"critical"},"azure.iam.excessive_permissions":{cloud:"azure",title:"Over-Privileged Role Assignment (Owner/Contributor)",what:"Users or service principals have been assigned Owner or Contributor roles at subscription scope.",why:"Overly broad roles allow full resource modification or deletion, risking account-wide damage.",fix:["Replace subscription-scope Owner/Contributor with resource-group or resource-scoped roles.","Use Azure AD Privileged Identity Management (PIM) for just-in-time elevation.","Review role assignments regularly with Azure Access Reviews."],docs:"https://learn.microsoft.com/en-us/azure/role-based-access-control/best-practices",severity:"critical"},"azure.iam.no_privileged_identity_mgmt":{cloud:"azure",title:"Azure AD Privileged Identity Management (PIM) Not Configured",what:"Privileged roles are permanently assigned rather than using just-in-time elevation via PIM.",why:"Permanent privileged assignments mean an attacker who compromises the account has constant admin access.",fix:["Enable Microsoft Entra Privileged Identity Management.","Convert all permanent privileged assignments to eligible assignments with approval workflows.","Set maximum activation duration of 4-8 hours for privileged roles."],docs:"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure",severity:"high"},"azure.nsg.ssh_open":{cloud:"azure",title:"NSG Allows Inbound SSH from Any IP (0.0.0.0/0)",what:"A Network Security Group rule allows TCP port 22 from the Internet.",why:"Open SSH on the internet is constantly brute-forced by automated scanners.",fix:["Remove the any-source SSH rule from the NSG.","Use Azure Bastion for SSH/RDP access — no open ports required.","If SSH is required, restrict the source IP to your corporate/VPN range."],docs:"https://learn.microsoft.com/en-us/azure/bastion/bastion-overview",severity:"critical"},"azure.nsg.rdp_open":{cloud:"azure",title:"NSG Allows Inbound RDP from Any IP (0.0.0.0/0)",what:"A Network Security Group rule allows TCP port 3389 from the Internet.",why:"Exposed RDP is the #1 ransomware entry point in Azure environments.",fix:["Delete the open RDP NSG rule immediately.","Use Azure Bastion for browser-based RDP without any open firewall rules.","Enable Just-in-Time VM Access via Defender for Cloud for temporary access."],docs:"https://learn.microsoft.com/en-us/azure/defender-for-cloud/just-in-time-access-usage",severity:"critical"},"azure.sql.public_access":{cloud:"azure",title:"Azure SQL Server Allows Public Network Access",what:"The SQL Server firewall allows connections from public internet IPs.",why:"Publicly reachable SQL servers are targeted for brute-force, injection, and credential stuffing.",fix:['Set "Deny public network access" to Yes on the SQL Server.',"Use Private Link or VNet Service Endpoints for all connectivity.","Audit and restrict firewall rules to specific known IPs."],docs:"https://learn.microsoft.com/en-us/azure/azure-sql/database/private-endpoint-overview",severity:"critical"},"azure.sql.no_tde":{cloud:"azure",title:"Transparent Data Encryption (TDE) Not Using CMK",what:"Azure SQL TDE is using a service-managed key instead of a customer-managed key.",why:"Without CMK-based TDE, you lack control over encryption key lifecycle.",fix:["Enable TDE with a customer-managed key stored in Azure Key Vault.","Assign a managed identity to the SQL Server for Key Vault access."],docs:"https://learn.microsoft.com/en-us/azure/azure-sql/database/transparent-data-encryption-byok-overview",severity:"medium"},"azure.sql.no_auditing":{cloud:"azure",title:"Azure SQL Server Auditing Disabled",what:"Database auditing is not enabled, so queries and logins are not logged.",why:"Without auditing, detecting SQL injection, data exfiltration, or privilege abuse is impossible.",fix:["Enable SQL Server Auditing and send logs to a Storage Account, Log Analytics, or Event Hub.","Retain audit logs for at least 90 days.","Enable Microsoft Defender for SQL for advanced threat detection."],docs:"https://learn.microsoft.com/en-us/azure/azure-sql/database/auditing-overview",severity:"high"},"azure.keyvault.no_expiry":{cloud:"azure",title:"Key Vault Secrets or Keys Have No Expiry Date",what:"Secrets, keys, or certificates in Azure Key Vault have no expiration configured.",why:"Non-expiring credentials are a persistent risk — if leaked, they remain valid indefinitely.",fix:["Set expiry dates on all Key Vault secrets, keys, and certificates.","Use Azure Key Vault Managed Identities to eliminate the need for long-lived secrets.","Enable Key Vault diagnostic logging and monitor for expiring items."],docs:"https://learn.microsoft.com/en-us/azure/key-vault/general/best-practices",severity:"high"},"azure.keyvault.no_soft_delete":{cloud:"azure",title:"Key Vault Soft Delete and Purge Protection Not Enabled",what:"Soft Delete and/or Purge Protection are not enabled on the Key Vault.",why:"Without these protections, a Key Vault or its contents can be permanently deleted instantly.",fix:["Enable Soft Delete and set retention to at least 90 days.","Enable Purge Protection to prevent permanent deletion during the retention period."],docs:"https://learn.microsoft.com/en-us/azure/key-vault/general/soft-delete-overview",severity:"high"},"azure.monitor.no_logs":{cloud:"azure",title:"Azure Activity Log Not Retained or Exported",what:"Activity Log entries are not being exported or retained beyond the default 90-day period.",why:"Without long-term logs, forensic investigation after a breach is impossible.",fix:["Create a Diagnostic Setting to export Activity Logs to Log Analytics, Storage, or Event Hub.","Set retention to at least 1 year for compliance requirements.","Enable Azure Monitor Alerts for critical activity (role assignments, policy changes, etc.)."],docs:"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/activity-log",severity:"high"},"azure.defender.not_enabled":{cloud:"azure",title:"Microsoft Defender for Cloud Not Fully Enabled",what:"Defender for Cloud plans (Servers, Storage, SQL, etc.) are not enabled for all resource types.",why:"Without Defender, threat detection, vulnerability assessment, and compliance monitoring are absent.",fix:["Enable Defender for Cloud plans for: Servers, Storage, SQL, Containers, and App Service.","Review the Secure Score dashboard and remediate high-impact recommendations.","Enable continuous export to SIEM for advanced correlation."],docs:"https://learn.microsoft.com/en-us/azure/defender-for-cloud/enable-enhanced-security",severity:"high"},"cognito.no_mfa":{cloud:"aws",title:"Cognito User Pool — MFA Not Required",what:"The Cognito User Pool does not require multi-factor authentication.",why:"Without MFA, compromised passwords give attackers full access to user accounts.",fix:['Set MFA to "Required" for the User Pool under Authentication → Multi-factor authentication.',"Enable TOTP (Time-based OTP) or SMS as the second factor.","Enable Cognito Advanced Security Mode to detect and block anomalous sign-ins."],docs:"https://docs.aws.amazon.com/cognito/latest/developerguide/user-pool-settings-mfa.html",severity:"high"},"cognito.no_advanced_security":{cloud:"aws",title:"Cognito Advanced Security Mode Disabled",what:"Cognito User Pool does not have Advanced Security Mode (ASM) enabled.",why:"Without ASM, Cognito cannot detect credential stuffing, account takeover, or anomalous sign-ins.",fix:["Enable Advanced Security Mode on the User Pool (Audit mode first, then Enforcement mode).","Review the risk events in the Cognito console to tune user risk handling.","Configure notifications for high-risk sign-in attempts."],docs:"https://docs.aws.amazon.com/cognito/latest/developerguide/cognito-user-pool-settings-advanced-security.html",severity:"medium"},"cognito.weak_password_policy":{cloud:"aws",title:"Cognito User Pool Has Weak Password Policy",what:"The User Pool password policy does not enforce minimum length, numbers, uppercase, or special characters.",why:"Weak passwords are easily brute-forced or guessed, leading to unauthorized account access.",fix:["Require a minimum password length of 12 characters.","Enforce uppercase, lowercase, numbers, and special characters.","Set a temporary password expiry of 7 days or less."],docs:"https://docs.aws.amazon.com/cognito/latest/developerguide/user-pool-settings-policies.html",severity:"medium"},"config.recorder_disabled":{cloud:"aws",title:"AWS Config Recorder Not Enabled",what:"AWS Config is not recording resource configuration changes in this region.",why:"Without Config, you lose visibility into configuration drift, change history, and compliance violations.",fix:["Enable the AWS Config recorder and delivery channel for all resource types.","Enable Config for all regions, or use an Aggregator for multi-region visibility.","Create Config Rules to continuously evaluate compliance (e.g. s3-bucket-public-read-prohibited)."],docs:"https://docs.aws.amazon.com/config/latest/developerguide/getting-started.html",severity:"high"},"backup.no_plan":{cloud:"aws",title:"No AWS Backup Plan Configured",what:"Critical resources (RDS, DynamoDB, EFS, EC2) have no automated backup plan.",why:"Without backups, accidental deletion, ransomware, or corruption can cause permanent data loss.",fix:["Create an AWS Backup plan with daily backups and 30-day retention minimum.","Add RDS, DynamoDB, EFS, EBS, and Aurora to the backup plan resource selection.","Enable Backup Vault Lock to protect backups from deletion.","Test restores quarterly to verify backup integrity."],docs:"https://docs.aws.amazon.com/aws-backup/latest/devguide/creating-a-backup-plan.html",severity:"high"},"redshift.publicly_accessible":{cloud:"aws",title:"Redshift Cluster Publicly Accessible",what:"The Redshift cluster is configured with PubliclyAccessible=true.",why:"Publicly accessible data warehouses expose sensitive analytics data to internet brute-force and SQL injection attacks.",fix:["Set PubliclyAccessible to false on the cluster.","Deploy Redshift in a private subnet with no internet route.","Use VPC endpoints or a bastion host for administrative access."],docs:"https://docs.aws.amazon.com/redshift/latest/mgmt/managing-clusters-vpc.html",severity:"critical"},"redshift.no_encryption":{cloud:"aws",title:"Redshift Cluster Not Encrypted",what:"The Redshift cluster is not encrypted at rest.",why:"Unencrypted data warehouses risk data exposure if storage is physically compromised or backups are accessed.",fix:["Enable cluster encryption using AWS KMS (requires cluster restore from snapshot).","Use a customer-managed KMS key for enhanced key control.","Enable audit logging to track all SQL queries and user activity."],docs:"https://docs.aws.amazon.com/redshift/latest/mgmt/working-with-db-encryption.html",severity:"high"},"redshift.no_audit_logging":{cloud:"aws",title:"Redshift Audit Logging Disabled",what:"Audit logging is not enabled for the Redshift cluster.",why:"Without audit logs, you cannot detect unauthorized queries, data exfiltration, or insider threats.",fix:["Enable audit logging in the Redshift cluster settings.","Set the S3 bucket destination and enable connection, user, and user activity logs.","Set bucket lifecycle rules to retain logs for at least 1 year."],docs:"https://docs.aws.amazon.com/redshift/latest/mgmt/db-auditing.html",severity:"medium"},"elasticache.no_auth":{cloud:"aws",title:"ElastiCache Redis — No AUTH Token",what:"The ElastiCache Redis cluster has no AUTH token (password) configured.",why:"Unauthenticated Redis is trivially exploitable: attackers can read all cached data, execute Lua scripts, and write to disk.",fix:["Enable AUTH token on the Redis replication group.","Restrict Security Group rules to only allow inbound access from application Security Groups.","Migrate to Redis 6+ and use Redis RBAC for fine-grained access control."],docs:"https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/auth.html",severity:"critical"},"elasticache.no_tls":{cloud:"aws",title:"ElastiCache — In-Transit Encryption Disabled",what:"In-transit encryption (TLS) is not enabled for the ElastiCache cluster.",why:"Data in transit between application and cache is visible to anyone with VPC network access.",fix:["Enable in-transit encryption when creating a new replication group.","Update application clients to use TLS connections.","Enable at-rest encryption simultaneously for defence in depth."],docs:"https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/in-transit-encryption.html",severity:"high"},"opensearch.public_endpoint":{cloud:"aws",title:"OpenSearch Domain Has Public Endpoint",what:"The OpenSearch/Elasticsearch domain is accessible from the public internet.",why:"Publicly accessible search clusters are frequently targeted for data theft and cryptomining.",fix:["Move the domain to a VPC using VPC access mode (requires a new domain).","If public access is required, enable fine-grained access control and require authentication.","Apply a restrictive resource-based policy limiting access to known IP ranges or IAM principals."],docs:"https://docs.aws.amazon.com/opensearch-service/latest/developerguide/vpc.html",severity:"critical"},"opensearch.no_encryption_at_rest":{cloud:"aws",title:"OpenSearch Domain Not Encrypted at Rest",what:"Encryption at rest is not enabled for the OpenSearch domain.",why:"Search indices often contain sensitive data; unencrypted storage risks exposure if storage is compromised.",fix:["Enable encryption at rest when creating the domain (cannot be enabled on existing domains).","Use a KMS customer-managed key for enhanced key control and audit logs.","Enable node-to-node encryption for defence in depth."],docs:"https://docs.aws.amazon.com/opensearch-service/latest/developerguide/encryption-at-rest.html",severity:"high"},"route53.dangling_dns":{cloud:"aws",title:"Route 53 — Dangling DNS Record",what:"A DNS record points to a resource (e.g. ELB, S3 bucket, CloudFront) that no longer exists.",why:"Attackers can claim the deleted resource and hijack the DNS record to serve malicious content or harvest credentials.",fix:["Audit all Route 53 records and verify each target resource still exists.","Delete CNAME/A/AAAA records that point to deprovisioned resources.","Use Route 53 Alias records which automatically resolve to AWS resources.","Automate DNS cleanup in your deprovisioning pipeline (IaC teardown)."],docs:"https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/troubleshooting-alias-records.html",severity:"high"},"route53.zone_transfer":{cloud:"aws",title:"Route 53 Zone Transfer Allowed",what:"The hosted zone allows unrestricted AXFR (zone transfer) requests.",why:"Zone transfers expose all DNS records to attackers, revealing internal infrastructure topology and potential targets.",fix:["Route 53 does not directly expose zone transfer; ensure private hosted zones are not accessible from public zones.","Restrict Route 53 hosted zone access using resource policies.","Avoid publishing internal hostnames in public hosted zones."],docs:"https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/hosted-zone-private-considerations.html",severity:"medium"},"secretsmanager.no_rotation":{cloud:"aws",title:"Secrets Manager — Rotation Disabled",what:"Automatic secret rotation is not configured for this secret.",why:"Long-lived, non-rotated credentials increase the blast radius of a secret compromise.",fix:["Enable automatic rotation using an AWS Lambda rotation function.","Use managed rotation for supported services (RDS, Aurora, Redshift).","Set rotation frequency to 30–90 days as per security policy."],docs:"https://docs.aws.amazon.com/secretsmanager/latest/userguide/rotating-secrets.html",severity:"high"},"secretsmanager.stale_secret":{cloud:"aws",title:"Secrets Manager — Secret Not Accessed in 180+ Days",what:"A secret has not been accessed in over 180 days.",why:"Stale, unused secrets are forgotten credentials that can be compromised without detection.",fix:["Verify whether the secret is still in use by any application or Lambda function.","Delete unused secrets to reduce your attack surface.","Enable resource-based policies to restrict access to only intended IAM principals."],docs:"https://docs.aws.amazon.com/secretsmanager/latest/userguide/best-practices.html",severity:"medium"},"codebuild.no_logging":{cloud:"aws",title:"CodeBuild Project — Logging Disabled",what:"CloudWatch or S3 logging is not configured for the CodeBuild project.",why:"Without build logs, you cannot audit what ran in your CI/CD pipeline, making supply-chain attack detection impossible.",fix:["Enable CloudWatch Logs for the CodeBuild project.","Optionally add S3 log export for long-term retention.","Create CloudWatch alarms for failed builds and privileged container usage."],docs:"https://docs.aws.amazon.com/codebuild/latest/userguide/monitoring-builds.html",severity:"medium"},"codebuild.privileged_mode":{cloud:"aws",title:"CodeBuild Project — Privileged Mode Enabled",what:"The CodeBuild project has privileged mode enabled (runs as root with Docker socket access).",why:"Privileged containers can escape the sandbox and access the host system; untrusted build code could compromise the builder.",fix:["Disable privileged mode unless building Docker images (required for Docker-in-Docker).","Use rootless Docker build tools (Kaniko, Podman) instead of Docker-in-Docker.","Restrict privileged builds to a separate, isolated build environment."],docs:"https://docs.aws.amazon.com/codebuild/latest/userguide/build-env-ref-compute-types.html",severity:"high"},"cloudformation.no_termination_protection":{cloud:"aws",title:"CloudFormation Stack — Termination Protection Disabled",what:"Stack termination protection is not enabled, allowing accidental or malicious stack deletion.",why:"Without termination protection, a single CLI command or misconfigured pipeline can destroy all stack resources.",fix:["Enable termination protection on all production stacks.","Use Service Control Policies (SCPs) to deny cloudformation:DeleteStack in production accounts.","Implement stack drift detection to catch manual changes."],docs:"https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/using-cfn-protect-stacks.html",severity:"medium"},"gcp.bigquery.public_dataset":{cloud:"gcp",title:"BigQuery Dataset Publicly Accessible",what:"The BigQuery dataset has IAM bindings granting allUsers or allAuthenticatedUsers access.",why:"Public BigQuery datasets expose sensitive analytics data to the entire internet or all Google account holders.",fix:["Remove allUsers and allAuthenticatedUsers from the dataset IAM policy.","Grant access only to specific service accounts and user groups.","Enable VPC Service Controls for BigQuery to restrict access by network.","Enable BigQuery audit logs (data access) to detect unauthorized reads."],docs:"https://cloud.google.com/bigquery/docs/access-control",severity:"critical"},"gcp.bigquery.no_cmek":{cloud:"gcp",title:"BigQuery Dataset Not Using CMEK",what:"The dataset uses Google-managed encryption keys instead of customer-managed keys.",why:"Google-managed keys provide no customer control over key revocation or audit trails.",fix:["Create a Cloud KMS key ring and key for BigQuery encryption.","Set the default encryption configuration on the dataset to use the CMEK.","Ensure the BigQuery service account has `cloudkms.cryptoKeyEncrypterDecrypter` role on the key."],docs:"https://cloud.google.com/bigquery/docs/customer-managed-encryption",severity:"medium"},"gcp.dns.dnssec_disabled":{cloud:"gcp",title:"Cloud DNS — DNSSEC Disabled",what:"DNSSEC is not enabled on the Cloud DNS managed zone.",why:"Without DNSSEC, the domain is vulnerable to DNS spoofing and cache poisoning attacks.",fix:["Enable DNSSEC on the managed zone in Cloud DNS.","Update the domain registrar DS records with the Cloud DNS-generated key.",'Use the "Transfer" state to coordinate DNSSEC key activation safely.'],docs:"https://cloud.google.com/dns/docs/dnssec-config",severity:"medium"},"gcp.secretmanager.no_rotation":{cloud:"gcp",title:"Secret Manager — No Rotation Policy",what:"The secret does not have an automatic rotation policy configured.",why:"Long-lived secrets that are never rotated increase the window of opportunity for attackers using stolen credentials.",fix:["Configure a rotation schedule on the secret (e.g. every 90 days).","Create a Cloud Scheduler job and Cloud Function to handle the rotation logic.","Subscribe to the `SECRET_ROTATE` Pub/Sub topic to trigger rotation automation."],docs:"https://cloud.google.com/secret-manager/docs/rotation-recommendations",severity:"medium"},"gcp.cloudrun.public_access":{cloud:"gcp",title:"Cloud Run Service — Unauthenticated Invocation Allowed",what:"The Cloud Run service allows allUsers to invoke it without authentication.",why:"Unauthenticated public services are exposed to abuse, scraping, and denial-of-wallet attacks.",fix:["Remove the `roles/run.invoker` binding for allUsers from the IAM policy.","Require authentication using Google identity tokens or Cloud IAP.","Use a load balancer with Cloud Armor security policy for public-facing services."],docs:"https://cloud.google.com/run/docs/securing/managing-access",severity:"high"},"azure.appservice.http_allowed":{cloud:"azure",title:"App Service — HTTP Not Redirected to HTTPS",what:"The web app allows plain HTTP connections without redirecting to HTTPS.",why:"Plaintext HTTP exposes session tokens, credentials, and sensitive data to network interception.",fix:['Enable "HTTPS Only" in the App Service TLS/SSL settings.',"Set the minimum TLS version to 1.2.","Configure App Service to redirect HTTP to HTTPS using a custom domain rule."],docs:"https://learn.microsoft.com/en-us/azure/app-service/configure-ssl-bindings#enforce-https",severity:"high"},"azure.appservice.remote_debugging":{cloud:"azure",title:"App Service — Remote Debugging Enabled",what:"Remote debugging is enabled on the App Service.",why:"Remote debugging opens a debugging port that can be used for unauthorized code execution and data access.",fix:["Disable remote debugging in the App Service Configuration → General settings.","Remote debugging auto-disables after 48 hours; do not re-enable in production.","Use Application Insights snapshot debugger as a safer alternative."],docs:"https://learn.microsoft.com/en-us/azure/app-service/troubleshoot-dotnet-visual-studio",severity:"high"},"azure.appservice.no_managed_identity":{cloud:"azure",title:"App Service — No Managed Identity",what:"The App Service does not use a system-assigned or user-assigned managed identity.",why:"Without managed identity, applications use hardcoded credentials (connection strings, API keys) that can be leaked.",fix:["Enable a system-assigned managed identity on the App Service.","Grant the identity only the permissions it needs (e.g. Key Vault Secrets User).","Replace all connection strings and API keys with managed identity authentication."],docs:"https://learn.microsoft.com/en-us/azure/app-service/overview-managed-identity",severity:"medium"},"azure.redis.non_ssl_port":{cloud:"azure",title:"Azure Cache for Redis — Non-SSL Port Enabled",what:"The Redis cache has the non-SSL port (6379) enabled.",why:"Data transmitted over unencrypted Redis connections can be intercepted within the network.",fix:["Disable the non-SSL port in the Azure Cache for Redis configuration.","Ensure all application clients connect using the SSL port (6380).","Configure the cache to allow only TLS 1.2 or higher."],docs:"https://learn.microsoft.com/en-us/azure/azure-cache-for-redis/cache-configure#access-ports",severity:"high"},"azure.loganalytics.short_retention":{cloud:"azure",title:"Log Analytics Workspace — Short Retention Period",what:"The Log Analytics workspace retains data for less than 90 days.",why:"Short retention periods mean forensic evidence and audit trails are lost before security investigations can complete.",fix:["Set data retention to at least 90 days (CIS recommends 1 year for audit logs).","Configure archive tier for older logs at lower cost.","Export critical logs to immutable Azure Blob Storage for long-term compliance."],docs:"https://learn.microsoft.com/en-us/azure/azure-monitor/logs/data-retention-archive",severity:"medium"},"azure.cosmosdb.public_endpoint":{cloud:"azure",title:"Cosmos DB — Public Network Access Enabled",what:"The Cosmos DB account allows access from all public networks.",why:"Unrestricted network access exposes the database endpoint to brute-force and credential stuffing from the internet.",fix:["Disable public network access in Cosmos DB networking settings.","Use Private Endpoint to restrict access to your VNet.","If public access is needed, configure IP allowlisting to known IP ranges only."],docs:"https://learn.microsoft.com/en-us/azure/cosmos-db/how-to-configure-private-endpoints",severity:"high"},"azure.cosmosdb.local_auth":{cloud:"azure",title:"Cosmos DB — Local Authentication Not Disabled",what:"The Cosmos DB account allows key-based (local) authentication in addition to Azure AD.",why:"Key-based authentication credentials are long-lived and not subject to Azure AD conditional access policies.",fix:["Set `disableLocalAuth: true` on the Cosmos DB account to enforce Azure AD-only authentication.","Assign the `Cosmos DB Built-in Data Contributor` role to the required service principals.","Rotate and then revoke all existing Cosmos DB keys."],docs:"https://learn.microsoft.com/en-us/azure/cosmos-db/how-to-setup-rbac",severity:"high"},"azure.servicebus.no_cmk":{cloud:"azure",title:"Service Bus — No Customer-Managed Key",what:"The Service Bus namespace uses Microsoft-managed keys for encryption at rest.",why:"Without CMK, you have no control over key rotation, revocation, or audit trails for encryption operations.",fix:["Create a Key Vault key and grant the Service Bus namespace managed identity access.","Configure CMK encryption on the Service Bus namespace (Premium tier required).","Enable soft delete and purge protection on the Key Vault."],docs:"https://learn.microsoft.com/en-us/azure/service-bus-messaging/configure-customer-managed-key",severity:"medium"},"azure.acr.admin_enabled":{cloud:"azure",title:"Container Registry — Admin Account Enabled",what:"The Azure Container Registry has the built-in admin account enabled.",why:"The admin account uses a shared password that cannot be scoped, audited, or revoked per-user.",fix:["Disable the admin account in the ACR Access keys settings.","Use Azure AD authentication with AcrPull/AcrPush role assignments instead.","Assign managed identities to services pulling images from ACR."],docs:"https://learn.microsoft.com/en-us/azure/container-registry/container-registry-authentication",severity:"high"},"azure.aks.public_endpoint":{cloud:"azure",title:"AKS API Server Has Public Endpoint",what:"The Azure Kubernetes Service API server is accessible from the public internet.",why:"A public Kubernetes API server is a prime target for credential theft and cluster takeover.",fix:["Enable Private Cluster to restrict API server to private network only.","If public endpoint is required, configure Authorised IP Ranges to restrict access.","Enable Azure AD integration and RBAC for fine-grained access control."],docs:"https://learn.microsoft.com/en-us/azure/aks/private-cluster",severity:"high"},"azure.aks.rbac_disabled":{cloud:"azure",title:"RBAC Disabled on AKS Cluster",what:"Kubernetes RBAC is not enabled on the AKS cluster.",why:"Without RBAC, all authenticated users have unrestricted access to all cluster resources.",fix:["Enable Azure AD integration with RBAC on the cluster.","Create namespace-scoped roles for application teams.","Use Azure AD groups to manage cluster access centrally."],docs:"https://learn.microsoft.com/en-us/azure/aks/manage-azure-rbac",severity:"high"},"cf.http_allowed":{cloud:"aws",title:"CloudFront Distribution Allows Plain HTTP",quickWin:!0,what:"One or more CloudFront cache behaviours are configured with ViewerProtocolPolicy=allow-all, meaning content can be served over unencrypted HTTP.",why:"Traffic served over HTTP is susceptible to man-in-the-middle (MITM) attacks, eavesdropping, and content injection. Modern browsers and compliance standards (PCI-DSS, HIPAA) require HTTPS everywhere.",fix:["In the CloudFront console, open the distribution and edit every cache behaviour.",'Set "Viewer Protocol Policy" to "Redirect HTTP to HTTPS" (preferred) or "HTTPS Only".',"Verify the origin also uses HTTPS to prevent the origin leg being unencrypted."],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/using-https.html",severity:"high"},"cf.no_waf":{cloud:"aws",title:"CloudFront Distribution Has No WAF Web ACL",quickWin:!1,what:"No AWS WAF Web ACL is associated with this CloudFront distribution, leaving it unprotected against common web exploits.",why:"Without WAF, the distribution is exposed to SQL injection, XSS, bad bots, DDoS layer-7 attacks, and scrapers. WAF managed rules block OWASP Top 10 attacks automatically.",fix:["Create a WAFv2 Web ACL in us-east-1 (required for CloudFront).",'Add the AWS Managed Rules group "AWSManagedRulesCommonRuleSet" as a first baseline rule.','Add "AWSManagedRulesBotControlRuleSet" if bot protection is needed.','Associate the Web ACL with the CloudFront distribution under "Security → WAF".','Set the default action to "Block" and tune rules for false positives.'],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/distribution-web-awswaf.html",severity:"high"},"cf.missing_security_headers":{cloud:"aws",title:"CloudFront Distribution Missing Security Response Headers",quickWin:!0,what:"The distribution does not return HSTS, X-Frame-Options, X-Content-Type-Options, or other security headers to browsers.",why:"Missing security headers expose users to clickjacking (no X-Frame-Options), MIME-sniffing attacks (no X-Content-Type-Options), and protocol downgrade attacks (no HSTS). These are required by PCI-DSS and common secure coding standards.",fix:["In CloudFront, go to Policies → Response Headers Policies and create a new policy.",'Enable "Strict-Transport-Security" with max-age=31536000 and includeSubDomains.','Enable "X-Frame-Options: DENY" (or SAMEORIGIN if embedding is needed).','Enable "X-Content-Type-Options: nosniff".','Enable "X-XSS-Protection: 1; mode=block" for legacy browser support.',"Attach the policy to all cache behaviours in the distribution."],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/adding-response-headers.html",severity:"medium"},"cf.no_hsts":{cloud:"aws",title:"CloudFront HSTS Header Not Configured",quickWin:!0,what:"A response headers policy exists but Strict-Transport-Security (HSTS) is not enabled.",why:"Without HSTS, attackers can strip HTTPS connections to plain HTTP (SSL-stripping attacks) even when the site supports HTTPS. HSTS instructs browsers to always use HTTPS for the domain.",fix:["Edit the existing Response Headers Policy for this distribution.","Under Security Headers, enable Strict-Transport-Security.","Set max-age to at least 31536000 (1 year) and enable includeSubDomains.","Once confident, consider adding the domain to the HSTS preload list."],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/adding-response-headers.html",severity:"medium"},"cf.outdated_tls":{cloud:"aws",title:"CloudFront Distribution Uses Outdated TLS Version",quickWin:!0,what:"The distribution's minimum TLS version is set to TLS 1.0 or TLS 1.1, which are deprecated protocols with known vulnerabilities.",why:"TLS 1.0 and 1.1 are susceptible to POODLE, BEAST, and CRIME attacks. PCI-DSS 3.2+ mandates TLS 1.2 minimum. Old TLS versions allow downgrades to weaker cipher suites.",fix:["Open the CloudFront distribution → Security → Security Policy.","Change the Security Policy (Minimum TLS Version) to TLSv1.2_2021.","Verify that all clients connecting to the distribution support TLS 1.2 (virtually all modern browsers do)."],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/secure-connections-supported-viewer-protocols-ciphers.html",severity:"high"},"cf.s3_origin_no_oac":{cloud:"aws",title:"CloudFront S3 Origin Without Origin Access Control",quickWin:!1,what:"S3 origins in this distribution are not protected by an Origin Access Control (OAC) or Origin Access Identity (OAI). The S3 bucket may be directly accessible from the internet, bypassing CloudFront.",why:"Without OAC/OAI, the S3 bucket must be publicly readable to serve content, exposing it to direct access that bypasses CloudFront WAF rules, rate limiting, and geo-restrictions. This also leaks the underlying S3 endpoint.",fix:["In CloudFront, create an Origin Access Control (OAC) — the modern replacement for OAI.","Associate the OAC with the S3 origin in the distribution.","Update the S3 bucket policy to only grant s3:GetObject to the CloudFront OAC principal (aws:SourceArn).","Remove any public-read ACLs or bucket policies from the S3 bucket.","Block public access on the S3 bucket using Block Public Access settings."],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/private-content-restricting-access-to-s3.html",severity:"high"},"cf.logging_disabled":{cloud:"aws",title:"CloudFront Access Logging Disabled",quickWin:!0,what:"Access logging is not configured for this CloudFront distribution, meaning no record of viewer requests is captured.",why:"Without access logs, incident investigation, abuse detection, bot analysis, and compliance reporting (PCI-DSS requires audit trails) are impossible. Logs are also required for threat intelligence correlation.",fix:["Create or designate an S3 bucket to store CloudFront logs (ideally a dedicated logging bucket with lifecycle rules).","In the distribution settings, enable Access Logging and set the log destination S3 bucket and optional prefix.","Consider enabling real-time logs via Kinesis Data Streams for immediate analysis.","Set up S3 lifecycle rules to archive logs to Glacier after 90 days and delete after 1 year."],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/AccessLogs.html",severity:"medium"},"cf.no_geo_restriction":{cloud:"aws",title:"CloudFront Distribution Has No Geo-Restriction",quickWin:!0,what:"This CloudFront distribution serves content globally with no geographic restrictions applied.",why:"If the application is intended for a specific region, serving content globally increases the attack surface from high-risk jurisdictions and may violate data sovereignty regulations (GDPR, data residency requirements).",fix:["Review the business requirement: does this application need global access?","If access should be limited, configure a CloudFront Geo-Restriction allowlist for permitted countries.","Alternatively, use AWS WAF geographic match conditions for more granular per-path control.","For compliance-sensitive data, verify geo-restrictions align with data residency obligations."],docs:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/georestrictions.html",severity:"low"},"cost.ebs_unattached":{cloud:"aws",title:"Unattached EBS Volume",what:'An EBS volume is in "available" state — not attached to any EC2 instance — and is accumulating storage charges.',why:"Unattached EBS volumes cost ~$0.08–$0.10/GB/month. A 1 TB volume unattached for a year costs ~$960 with no benefit.",fix:["Identify the volume: `aws ec2 describe-volumes --filters Name=status,Values=available`","Snapshot if the data may be needed: `aws ec2 create-snapshot --volume-id vol-xxx`","Delete the volume: `aws ec2 delete-volume --volume-id vol-xxx`",'Use AWS Cost Explorer with the "Unattached EBS Volumes" recommendation to find all such volumes.'],docs:"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ebs-deleting-volume.html",severity:"medium",quickWin:!0},"cost.ec2_stopped":{cloud:"aws",title:"Stopped EC2 Instance",what:"A stopped EC2 instance is still incurring charges for its attached EBS volumes, Elastic IPs, and data transfer.",why:"Even stopped, the associated storage and IP resources are billed. If the instance is not needed, these costs add up over time.",fix:["Determine if the instance is still required — check with the owner tag.","If no longer needed, terminate: `aws ec2 terminate-instances --instance-ids i-xxx`","If needed occasionally, consider converting to a spot-interruptible workload or use Lambda/Fargate for on-demand compute."],docs:"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-instance-lifecycle.html",severity:"medium",quickWin:!0},"cost.rds_stopped":{cloud:"aws",title:"Stopped RDS Instance",what:"A stopped RDS instance continues to accumulate storage and IOPS charges. AWS will also automatically restart it after 7 days.",why:"RDS storage bills regardless of state. An unused db.r5.large with 500 GB storage costs ~$100+/month in storage alone.",fix:["If the database is no longer needed, take a final snapshot and delete the instance.","For intermittent workloads, consider migrating to Aurora Serverless v2 which can scale to 0 ACUs.","To delete: `aws rds delete-db-instance --db-instance-identifier xxx --final-db-snapshot-identifier xxx-final`"],docs:"https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_StopInstance.html",severity:"medium",quickWin:!0},"cost.ec2_on_demand_large":{cloud:"aws",title:"Large On-Demand Instance — Consider Reserved Pricing",what:"A large EC2 instance is running on on-demand pricing. If it runs 24/7, a Reserved Instance or Savings Plan would be significantly cheaper.",why:"1-year no-upfront Reserved Instances save ~30–40%, and 3-year saves up to 60% versus on-demand pricing.",fix:['Analyse usage in AWS Cost Explorer → "Savings Plans" or "Reserved Instances" recommendations.',"Purchase a Compute Savings Plan if workload varies across instance families.","Purchase an EC2 Instance Savings Plan for steady-state workloads with predictable instance types."],docs:"https://aws.amazon.com/savingsplans/",severity:"low"},"cost.lambda_oversized":{cloud:"aws",title:"Lambda Function Over-Provisioned Memory",what:"A Lambda function is allocated very high memory (8 GB+). Unless it processes large objects, this is likely over-provisioned.",why:"Lambda billing is based on GB-seconds. Halving memory from 8 GB to 4 GB on a function running 1M times/month at 1s each saves ~$84/month.",fix:["Run AWS Lambda Power Tuning (open-source Step Functions state machine) to find the optimal memory.","Review CloudWatch metrics for actual memory usage (max memory used vs configured).","Right-size to the nearest allocation above the p95 memory usage."],docs:"https://docs.aws.amazon.com/lambda/latest/dg/configuration-memory.html",severity:"low",quickWin:!0},"cost.ec2_missing_tags":{cloud:"aws",title:"EC2 Instance Missing Cost-Allocation Tags",what:"An EC2 instance is missing tags such as Owner, CostCenter, Environment, or Project that are required for cost attribution.",why:"Without cost-allocation tags, spend cannot be split by team/project in AWS Cost Explorer, making it impossible to charge back or optimise by business unit.",fix:["Apply missing tags via Console or: `aws ec2 create-tags --resources i-xxx --tags Key=Owner,Value=team`","Enforce tagging via AWS Tag Policies or Service Control Policies (SCPs) in AWS Organizations.",'Use AWS Config rule "required-tags" to alert on untagged resources automatically.'],docs:"https://docs.aws.amazon.com/awsaccountbilling/latest/aboutv2/cost-alloc-tags.html",severity:"low",quickWin:!0},"cost.s3_missing_tags":{cloud:"aws",title:"S3 Bucket Missing Cost-Allocation Tags",what:"An S3 bucket is missing cost-allocation tags. S3 is often a top-3 AWS cost driver and tagging is critical for accurate attribution.",why:"Untagged S3 buckets obscure storage costs across teams. Large buckets (100 TB+) can cost $2,000+/month, making attribution essential.",fix:["Add tags: `aws s3api put-bucket-tagging --bucket BUCKET --tagging TagSet=[{Key=Owner,Value=team}]`","Enable Cost Allocation Tags in the Billing console to activate them for Cost Explorer."],docs:"https://docs.aws.amazon.com/AmazonS3/latest/userguide/CostAllocTagging.html",severity:"low",quickWin:!0},"cost.rds_missing_tags":{cloud:"aws",title:"RDS Instance Missing Cost-Allocation Tags",what:"An RDS instance is missing cost-allocation tags needed for billing attribution.",why:"RDS can be one of the largest AWS cost contributors. Without tags, database costs cannot be attributed to a specific application or team.",fix:["Add tags: `aws rds add-tags-to-resource --resource-name arn:aws:rds:... --tags Key=Owner,Value=team`"],docs:"https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_Tagging.html",severity:"low",quickWin:!0},"cost.gce_terminated":{cloud:"gcp",title:"Terminated GCE Instance with Persistent Disks",what:"A GCE instance is in TERMINATED state. Its attached persistent disks continue to incur storage charges.",why:"Persistent disks cost $0.04–$0.17/GB/month regardless of VM state. A 1 TB SSD disk costs ~$170/month with no compute value.",fix:["Delete the instance and disks: `gcloud compute instances delete INSTANCE --delete-disks=all --zone ZONE`","Or snapshot disks first: `gcloud compute disks snapshot DISK --snapshot-names SNAPSHOT --zone ZONE`","Use Committed Use Discounts for instances that run 24/7."],docs:"https://cloud.google.com/compute/docs/instances/deleting-instance",severity:"medium",quickWin:!0},"cost.gce_missing_labels":{cloud:"gcp",title:"GCE Instance Missing Cost Labels",what:"A GCE instance is missing labels used for cost attribution in GCP Billing Export.",why:"GCP uses labels (not tags) for cost attribution. Without labels like owner, environment, and cost-center, spend cannot be split in BigQuery billing exports.",fix:["Add labels: `gcloud compute instances add-labels INSTANCE --labels=owner=team,environment=prod,cost-center=123 --zone ZONE`","Enforce labelling using GCP Organization Policy constraints/compute.requireOsLogin or custom Terraform/Pulumi policies."],docs:"https://cloud.google.com/resource-manager/docs/creating-managing-labels",severity:"low",quickWin:!0},"cost.gcs_missing_labels":{cloud:"gcp",title:"GCS Bucket Missing Cost Labels",what:"A Cloud Storage bucket is missing labels needed for cost attribution.",why:"Storage costs in GCP are attributed via labels in the Billing Export. Without labels, storage costs cannot be allocated to teams or projects.",fix:["Add labels via Console or: `gsutil label ch -l owner:team -l environment:prod gs://BUCKET`"],docs:"https://cloud.google.com/storage/docs/using-bucket-labels",severity:"low",quickWin:!0},"cost.azure_vm_deallocated":{cloud:"azure",title:"Deallocated Azure VM Still Incurring Disk Costs",what:"An Azure VM is in the Deallocated state. While compute charges stop, its managed disk(s) continue to accrue storage costs.",why:"Managed disk costs range from $4–$20+/month per disk (P10–P30 tiers). A deallocated VM with 3 disks can cost $30–$60/month.",fix:["Delete the VM and disks via Portal or: `az vm delete --resource-group RG --name VM --yes`","Capture an image first if the VM may be needed: `az vm capture --resource-group RG --name VM --vhd-name-prefix PREFIX`","For periodic workloads, use Azure Container Instances (pay-per-second) instead of persistent VMs."],docs:"https://learn.microsoft.com/en-us/azure/virtual-machines/states-billing",severity:"medium",quickWin:!0},"cost.azure_missing_tags":{cloud:"azure",title:"Azure Resource Missing Cost-Allocation Tags",what:"An Azure resource is missing tags required for cost management and attribution.",why:"Azure Cost Management uses tags for subscription-level breakdowns. Without tags, it is impossible to split costs by team, project, or environment.",fix:["Add tags via Portal or: `az resource tag --tags Owner=team Environment=prod --ids RESOURCE_ID`",'Enforce tagging via Azure Policy with the "Require a tag on resources" built-in policy.','Use the "Tag inheritance" policy to propagate tags from resource groups to resources automatically.'],docs:"https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources",severity:"low",quickWin:!0}},l={aws:{critical:["sg.ssh_open","s3.public_access","iam.wildcard_action","cloudtrail.disabled","lambda.hardcoded_secret","elasticache.no_auth","opensearch.public_endpoint","redshift.publicly_accessible"],high:["s3.no_encryption","rds.publicly_accessible","iam.unused_keys","guardduty.disabled","eks.public_endpoint","cognito.no_mfa","config.recorder_disabled","backup.no_plan","secretsmanager.no_rotation","codebuild.privileged_mode","elasticache.no_tls","cf.no_waf","cf.http_allowed","cf.outdated_tls","cf.s3_origin_no_oac"],medium:["kms.no_rotation","vpc.no_flow_logs","s3.no_versioning","alb.no_waf","cognito.no_advanced_security","route53.dangling_dns","cloudformation.no_termination_protection","codebuild.no_logging","cf.missing_security_headers","cf.no_hsts","cf.logging_disabled"]},gcp:{critical:["gcp.firewall.ssh_open","gcp.storage.public_bucket","gcp.iam.no_mfa","gcp.logging.disabled","gcp.sql.public_ip","gcp.bigquery.public_dataset"],high:["gcp.iam.service_account_key","gcp.iam.primitive_roles","gcp.gke.public_endpoint","gcp.compute.os_not_patched","gcp.monitoring.no_alerts","gcp.cloudrun.public_access"],medium:["gcp.kms.no_rotation","gcp.vpc.no_flow_logs","gcp.storage.no_versioning","gcp.bigquery.no_cmek","gcp.dns.dnssec_disabled","gcp.secretmanager.no_rotation"]},azure:{critical:["azure.nsg.ssh_open","azure.storage.public_blob","azure.iam.no_mfa","azure.iam.excessive_permissions","azure.sql.public_access","azure.cosmosdb.public_endpoint"],high:["azure.vm.no_disk_encryption","azure.vm.no_mde","azure.storage.no_https","azure.sql.no_auditing","azure.keyvault.no_expiry","azure.acr.admin_enabled","azure.redis.non_ssl_port","azure.appservice.http_allowed","azure.cosmosdb.local_auth"],medium:["azure.storage.no_cmk","azure.sql.no_tde","azure.monitor.no_logs","azure.loganalytics.short_retention","azure.servicebus.no_cmk","azure.appservice.no_managed_identity"]}};function d(t){if(!t)return null;const a=(t.rule_id||"").toLowerCase(),r=(t.resource_type||"").toLowerCase(),o=(t.cloud||"").toLowerCase();if(a&&n[a])return n[a];for(const e of Object.keys(n)){const[i]=e.split(".");if(r&&r.startsWith(i))return n[e]}if(o&&o!=="aws"){const e=o+".";for(const i of Object.keys(n))if(i.startsWith(e))return n[i]}const s=(t.severity||"medium").toLowerCase();return{cloud:o||"aws",title:t.title||"Security Finding",what:t.title||"A security issue was detected in your cloud environment.",why:"This finding may indicate a misconfiguration or security gap that could be exploited.",fix:["Review the affected resource and apply the principle of least privilege.","Consult the cloud provider security best practices documentation for this service.","Consider enabling native security monitoring (GuardDuty / Security Command Center / Defender for Cloud) to continuously detect and alert on this issue."],docs:o==="gcp"?"https://cloud.google.com/security/best-practices":o==="azure"?"https://learn.microsoft.com/en-us/azure/security/fundamentals/best-practices-and-patterns":"https://docs.aws.amazon.com/security/",severity:s}}function u(t,a,r=5){const o=(t||"aws").toLowerCase(),s=l[o]||l.aws,e=[];(a.critical||0)>0&&e.push(...s.critical||[]),(a.high||0)>0&&e.push(...s.high||[]),(a.medium||0)>0&&e.push(...s.medium||[]),e.length||e.push(...s.critical||[],...s.high||[]);const i=new Set;return e.filter(c=>i.has(c)?!1:(i.add(c),!0)).slice(0,r).map(c=>n[c]).filter(Boolean)}export{n as R,d as a,u as g};
